      )}

      {/* ===== TAB: Settings (Change Admin Password) ===== */}
      {activeTab === "settings" && (
        <div className="animate-fade-in max-w-lg mx-auto">
          <div className="card-royal">
            <h3 className="section-title mb-5"><KeyRound size={16} className="text-gold-600" /> เปลี่ยนรหัสผ่านผู้ดูแล</h3>
            <div className="space-y-4">
              <div>
                <label className="text-sm font-semibold text-royal-600 mb-1.5 block">รหัสผ่านใหม่</label>
                <div className="relative">
                  <Lock size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-royal-300 pointer-events-none z-10" />
                  <input
                    className="input-royal !pl-10"
                    type="password"
                    placeholder="รหัสผ่านใหม่ (อย่างน้อย 4 ตัวอักษร)"
                    value={newPassword}
                    onChange={(e) => setNewPassword(e.target.value)}
                  />
                </div>
              </div>
              <div>
                <label className="text-sm font-semibold text-royal-600 mb-1.5 block">ยืนยันรหัสผ่านใหม่</label>
                <div className="relative">
                  <Lock size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-royal-300 pointer-events-none z-10" />
                  <input
                    className="input-royal !pl-10"
                    type="password"
                    placeholder="พิมพ์รหัสผ่านอีกครั้ง"
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    onKeyDown={(e) => e.key === "Enter" && handleChangePassword()}
                  />
                </div>
              </div>
              {changePwError && (
                <div className="bg-red-50 border border-red-200 rounded-lg p-3 text-sm text-red-700 text-center">
                  {changePwError}
                </div>
              )}
              {changePwMsg && (
                <div className="bg-green-50 border border-green-200 rounded-lg p-3 text-sm text-green-700 text-center flex items-center justify-center gap-1.5">
                  <CheckCircle size={15} /> {changePwMsg}
                </div>
              )}
              <button
                className="btn-gold w-full flex items-center justify-center gap-2 py-3"
                onClick={handleChangePassword}
                disabled={changingPw || !newPassword || !confirmPassword}
              >
                <KeyRound size={16} /> {changingPw ? "กำลังเปลี่ยน..." : "เปลี่ยนรหัสผ่าน"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import type { NextApiRequest, NextApiResponse } from "next";
import prisma from "../../../lib/prisma";
import bcrypt from "bcryptjs";
import { randomBytes } from "crypto";

function generateUsername(prefix: string, index: number): string {
  const slug = prefix.replace(/[^a-zA-Z0-9ก-๙]/g, "").slice(0, 10);
  const rand = randomBytes(2).toString("hex");
  return `${slug}-${rand}`;
}

function generatePassword(): string {
  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789";
  let pw = "";
  const bytes = randomBytes(8);
  for (let i = 0; i < 8; i++) pw += chars[bytes[i] % chars.length];
  return pw;
}

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  if (req.method !== "POST") return res.status(405).end();

  const control = await prisma.controlState.findUnique({ where: { id: 1 } });
  const loginMode = control?.loginMode || "PER_SCHOOL";
  const results: { name: string; username: string; password: string; type: string }[] = [];

  if (loginMode === "PER_SCHOOL") {
    const schools = await prisma.school.findMany({ orderBy: { id: "asc" } });
    for (const school of schools) {
      const username = generateUsername(school.name, school.id);
      const password = generatePassword();
      const hash = await bcrypt.hash(password, 10);
      await prisma.school.update({
        where: { id: school.id },
        data: { username, passwordHash: hash },
      });
      results.push({ name: school.name, username, password, type: "school" });
    }
  } else {
    const users = await prisma.user.findMany({ include: { school: true }, orderBy: { id: "asc" } });
    for (const user of users) {
      const username = generateUsername(user.name, user.id);
      const password = generatePassword();
      const hash = await bcrypt.hash(password, 10);
      const qrToken = randomBytes(16).toString("hex");
      await prisma.user.update({
        where: { id: user.id },
        data: { username, passwordHash: hash, loginQrToken: qrToken },
      });
      results.push({ name: `${user.name} (${user.school.name})`, username, password, type: "user" });
    }
  }

  return res.status(200).json({ credentials: results, loginMode });
}

